// GENERATED BY NAPL from schemas_map.napl — edit the prompt, not this file

use schemas_ordered_map::OrderedMap;
use serde::{Deserialize, Serialize};

fn default_version() -> u32 {
    2
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct PromptTargetRecord {
    #[serde(rename = "promptHashAtGen", default, skip_serializing_if = "Option::is_none")]
    pub prompt_hash_at_gen: Option<String>,
    #[serde(default)]
    pub files: Vec<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub unattributed: Option<bool>,
