#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct PromptRecord {
    pub module: String,
    #[serde(rename = "promptHash")]
    pub prompt_hash: String,
    #[serde(rename = "declaredTargets", default)]
    pub declared_targets: Vec<String>,
    #[serde(default)]
    pub targets: OrderedMap<PromptTargetRecord>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct FileRecord {
    pub target: String,
    pub hash: String,
    #[serde(default)]
    pub prompts: Vec<String>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct NaplMap {
    #[serde(default = "default_version")]
    pub version: u32,
    #[serde(default)]
    pub prompts: OrderedMap<PromptRecord>,
    #[serde(default)]
    pub files: OrderedMap<FileRecord>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ModuleFile {
    pub target: String,
    pub file_path: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FileInput {
    pub file_path: String,
    pub hash: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AttributionInput {
    pub rel: String,
    pub module: String,
    pub prompt_hash: String,
    pub target: String,
    pub declared_targets: Vec<String>,
    pub files: Vec<FileInput>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct UnattributedInput {
    pub rel: String,
    pub module: String,
    pub prompt_hash: String,
    pub target: String,
    pub declared_targets: Vec<String>,
    pub files: Vec<String>,
}

pub fn empty_map() -> NaplMap {
    NaplMap {
        version: 2,
        prompts: OrderedMap::new(),
        files: OrderedMap::new(),
    }
}

pub fn parse_map(raw: &str) -> Result<NaplMap, String> {
    let map: NaplMap = serde_json::from_str(raw).map_err(|e| e.to_string())?;
    if map.version != 2 {
        return Err("unsupported map version".to_string());
    }
    Ok(map)
