pub fn prompts_for_module(map: &NaplMap, module: &str) -> Vec<String> {
    map.prompts
        .iter()
        .filter(|(_, record)| record.module == module)
        .map(|(rel, _)| rel.clone())
        .collect()
}

pub fn has_module(map: &NaplMap, module: &str) -> bool {
    map.prompts.iter().any(|(_, record)| record.module == module)
}

pub fn declared_targets_for_module(map: &NaplMap, module: &str) -> Vec<String> {
    let mut seen = Vec::new();
    for (_, record) in map.prompts.iter() {
        if record.module != module {
            continue;
        }
        for target in &record.declared_targets {
            if !seen.contains(target) {
                seen.push(target.clone());
            }
        }
    }
    seen
}

pub fn files_for_module(map: &NaplMap, module: &str) -> Vec<ModuleFile> {
    let mut result: Vec<ModuleFile> = Vec::new();
    for (_, record) in map.prompts.iter() {
        if record.module != module {
            continue;
        }
        for (target, target_record) in record.targets.iter() {
            for file_path in &target_record.files {
                let already = result
                    .iter()
                    .any(|mf| &mf.target == target && &mf.file_path == file_path);
                if !already {
                    result.push(ModuleFile {
                        target: target.clone(),
                        file_path: file_path.clone(),
                    });
                }
            }
        }
    }
    result
}

pub fn is_prompt_gen_stale(
    record: Option<&PromptRecord>,
    target: &str,
    prompt_hash: &str,
    force: bool,
) -> bool {
    if force {
        return true;
    }
    let Some(record) = record else {
        return true;
    };
    let Some(target_record) = record.targets.get(target) else {
        return true;
    };
    if target_record.unattributed == Some(true) {
        return true;
    }
    match &target_record.prompt_hash_at_gen {
        Some(hash) => hash != prompt_hash,
        None => true,
    }
}

fn detach_file(map: &mut NaplMap, rel: &str, file_path: &str) {
    let Some(file_record) = map.files.get_mut(file_path) else {
        return;
    };
    file_record.prompts.retain(|p| p != rel);
    if file_record.prompts.is_empty() {
        map.files.remove(file_path);
    }
}

pub fn record_attribution(map: &mut NaplMap, input: &AttributionInput) {
    let mut targets = map
        .prompts
        .get(&input.rel)
        .map(|record| record.targets.clone())
        .unwrap_or_default();

    let prior_files: Vec<String> = targets
        .get(&input.target)
        .map(|target_record| target_record.files.clone())
        .unwrap_or_default();

    let new_file_paths: Vec<String> = input.files.iter().map(|f| f.file_path.clone()).collect();

    for prior_file in &prior_files {
        if !new_file_paths.contains(prior_file) {
            detach_file(map, &input.rel, prior_file);
        }
    }

    targets.insert(
        input.target.clone(),
        PromptTargetRecord {
            prompt_hash_at_gen: Some(input.prompt_hash.clone()),
            files: new_file_paths.clone(),
            unattributed: None,
        },
    );

    map.prompts.insert(
        input.rel.clone(),
        PromptRecord {
            module: input.module.clone(),
            prompt_hash: input.prompt_hash.clone(),
            declared_targets: input.declared_targets.clone(),
            targets,
        },
    );

    for file in &input.files {
        match map.files.get_mut(&file.file_path) {
            Some(existing) => {
                existing.target = input.target.clone();
                existing.hash = file.hash.clone();
                if !existing.prompts.iter().any(|p| p == &input.rel) {
                    existing.prompts.push(input.rel.clone());
                }
            }
            None => {
                map.files.insert(
                    file.file_path.clone(),
                    FileRecord {
                        target: input.target.clone(),
                        hash: file.hash.clone(),
                        prompts: vec![input.rel.clone()],
                    },
                );
            }
        }
    }
}

pub fn record_unattributed(map: &mut NaplMap, input: &UnattributedInput) {
    let mut targets = map
        .prompts
        .get(&input.rel)
        .map(|record| record.targets.clone())
        .unwrap_or_default();

    let prior_files: Vec<String> = targets
        .get(&input.target)
        .map(|target_record| target_record.files.clone())
        .unwrap_or_default();

    for prior_file in &prior_files {
        detach_file(map, &input.rel, prior_file);
    }

    targets.insert(
        input.target.clone(),
        PromptTargetRecord {
            prompt_hash_at_gen: None,
            files: input.files.clone(),
            unattributed: Some(true),
        },
    );

    map.prompts.insert(
        input.rel.clone(),
        PromptRecord {
            module: input.module.clone(),
            prompt_hash: input.prompt_hash.clone(),
            declared_targets: input.declared_targets.clone(),
            targets,
        },
    );
}

