    }

    #[test]
    fn map_round_trips_through_json() {
        let mut map = empty_map();
        record_attribution(
            &mut map,
            &AttributionInput {
                rel: "a.napl".to_string(),
                module: "m".to_string(),
                prompt_hash: "h1".to_string(),
                target: "rust".to_string(),
                declared_targets: vec!["rust".to_string()],
                files: vec![FileInput {
                    file_path: "src/a.rs".to_string(),
                    hash: "fh1".to_string(),
                }],
            },
        );

        let json = map_to_json(&map);
        assert!(json.ends_with('\n'));
        let reparsed = parse_map(&json).unwrap();
        assert_eq!(reparsed, map);
    }

