    #[test]
    fn is_prompt_gen_stale_covers_all_cases() {
        assert!(is_prompt_gen_stale(None, "rust", "h1", true));
        assert!(is_prompt_gen_stale(None, "rust", "h1", false));

        let mut targets = OrderedMap::new();
        targets.insert(
            "rust".to_string(),
            PromptTargetRecord {
                prompt_hash_at_gen: Some("h1".to_string()),
                files: vec!["a.rs".to_string()],
                unattributed: None,
            },
        );
        let record = PromptRecord {
            module: "m".to_string(),
            prompt_hash: "h1".to_string(),
            declared_targets: vec![],
            targets,
        };

        assert!(!is_prompt_gen_stale(Some(&record), "rust", "h1", false));
        assert!(is_prompt_gen_stale(Some(&record), "rust", "h2", false));
        assert!(is_prompt_gen_stale(Some(&record), "ts", "h1", false));

        let mut targets2 = OrderedMap::new();
        targets2.insert(
            "rust".to_string(),
            PromptTargetRecord {
                prompt_hash_at_gen: None,
                files: vec!["a.rs".to_string()],
                unattributed: Some(true),
            },
        );
        let record2 = PromptRecord {
            module: "m".to_string(),
            prompt_hash: "h1".to_string(),
            declared_targets: vec![],
            targets: targets2,
        };
        assert!(is_prompt_gen_stale(Some(&record2), "rust", "h1", false));
    }

    #[test]
    fn record_attribution_detaches_orphaned_prior_files() {
        let mut map = empty_map();
        record_attribution(
            &mut map,
            &AttributionInput {
                rel: "a.napl".to_string(),
                module: "m".to_string(),
                prompt_hash: "h1".to_string(),
                target: "rust".to_string(),
                declared_targets: vec![],
                files: vec![
                    FileInput { file_path: "src/a.rs".to_string(), hash: "f1".to_string() },
                    FileInput { file_path: "src/b.rs".to_string(), hash: "f2".to_string() },
                ],
            },
        );
        assert!(map.files.contains_key("src/a.rs"));
        assert!(map.files.contains_key("src/b.rs"));

        record_attribution(
            &mut map,
            &AttributionInput {
                rel: "a.napl".to_string(),
                module: "m".to_string(),
                prompt_hash: "h2".to_string(),
                target: "rust".to_string(),
                declared_targets: vec![],
                files: vec![FileInput { file_path: "src/a.rs".to_string(), hash: "f1b".to_string() }],
            },
        );

        assert!(map.files.contains_key("src/a.rs"));
        assert!(!map.files.contains_key("src/b.rs"));
        let record = map.prompts.get("a.napl").unwrap();
        let target_record = record.targets.get("rust").unwrap();
        assert_eq!(target_record.prompt_hash_at_gen, Some("h2".to_string()));
        assert_eq!(target_record.files, vec!["src/a.rs".to_string()]);
    }

