        let record = map.prompts.get("a.napl").unwrap();
        let target_record = record.targets.get("rust").unwrap();
        assert_eq!(target_record.unattributed, Some(true));
        assert_eq!(target_record.prompt_hash_at_gen, None);
        assert_eq!(
            target_record.files,
            vec!["src/a.rs".to_string(), "src/orphan.rs".to_string()]
